external_knowledge:
- 'this recent year' refers to 2023;
- 'measure of how frequently they were accessed' corresponds to the number of access logs for each country, ranked from highest to lowest;
- 'happiness standing' refers to the happiness rank of each country.

sql:
SELECT AVG(happiness_score) AS average_happiness_score
FROM happiness_scores
WHERE economy_gdp_per_capita > (
    SELECT AVG(economy_gdp_per_capita)
    FROM happiness_scores
);
